#include <stdio.h>
#include <math.h>

int multiply(int a1, int b1, int c1, int a2, int b2, int c2, int* A, int* B, int* C) {
    int s = (a1*a2 + b1*b2 + c1*c2) + (a1*b2 + b1*a2) + (c1 + c2);
    int t = floor(s/2.0) + 16*(c1 + c2) - c1*c2;
    *A = (t - 2*(a1*b2 + b1*a2) - (a1*c2 + c1*a2) + 33*(a1 + a2) + (b1*b2 - a1*a2)) - 540;
    *B = (t - 5*(a1*b2 + b1*a2) - (c1*b2 + b1*c2) + 33*(b1 + b2) + (2*b1*b2 + 4*a1*a2)) - 540;
    *C = 24;
    if (s % 2 != 0) {
        *A -= 7;
        *B -= 7;
        *C = 11;
    }
    return 1;
}

int is_prime(int a, int b, int c) {
    for (int i = -100; i <= 100; i++) {
        for (int j = -100; j <= 100; j++) {
            for (int k = 11; k <= 24; k += 13) {
                int A, B, C;
                multiply(i, j, k, a, b, c, &A, &B, &C);
                if (A == 0 && B == 0 && C == 11) return 0;
                if (A == 4 && B == 4 && C == 24) return 0;
            }
        }
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int a, b, c;
        scanf("%d %d %d", &a, &b, &c);
        if (is_prime(a, b, c)) printf("PRIME\n");
        else printf("NOT PRIME\n");
    }
    return 0;
}

